pure fn count_frequency(s: Text) -> [[Any]] {
    chars = split(s, "")
    uniq = unique(chars)
    result = []
    for c in uniq {
        cnt = 0
        for d in chars {
            if d == c { cnt = cnt + 1 }
        }
        result = append(result, [c, cnt])
    }
    return result
}

entry main(x: Text) {
    return count_frequency("mississippi")
}

