pure fn fib_sequence(count: Number) -> [Number] {
    seq = [0, 1]
    for i in range(2, count) {
        a = get(seq, i - 1)
        b = get(seq, i - 2)
        seq = append(seq, a + b)
    }
    return seq
}

entry main(x: Text) {
    return fib_sequence(10)
}

