pure fn parse_date(d: Text) -> [Number] {
    parts = split(d, "-")
    y = to_number(get(parts, 0))
    m = to_number(get(parts, 1))
    day = to_number(get(parts, 2))
    return [y, m, day]
}

pure fn days_since_epoch(date: [Number]) -> Number {
    y = get(date, 0)
    m = get(date, 1)
    d = get(date, 2)
    month_days = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
    days = 0
    for yy in range(1, y) {
        days = days + 365
        if (yy % 400 == 0 or (yy % 4 == 0 and yy % 100 != 0)) {
            days = days + 1
        }
    }
    for mm in range(1, m) {
        md = get(month_days, mm - 1)
        days = days + md
        if mm == 2 and (y % 400 == 0 or (y % 4 == 0 and y % 100 != 0)) {
            days = days + 1
        }
    }
    days = days + d
    return days
}

pure fn days_between(d1: [Number], d2: [Number]) -> Number {
    ds1 = days_since_epoch(d1)
    ds2 = days_since_epoch(d2)
    return ds2 - ds1
}

