pure fn mean(nums: [Number]) -> Number {
    total = 0
    for n in nums {
        total = total + n
    }
    return total / length(nums)
}

pure fn stddev(nums: [Number]) -> Number {
    m = mean(nums)
    sum_sq = 0
    for n in nums {
        diff = n - m
        sum_sq = sum_sq + diff * diff
    }
    variance = sum_sq / length(nums)
    return pow(variance, 0.5)
}

