pure fn parse_and_sort(s: Text) -> [[Text, Number]] {
    entries = split(s, ",")
    pairs = []
    for e in entries {
        parts = split(e, ":")
        city = get(parts, 0)
        lat = to_number(get(parts, 1))
        pairs = append(pairs, [city, lat])
    }
    flipped = []
    for p in pairs {
        flipped = append(flipped, [get(p, 1), get(p, 0)])
    }
    sorted = sort(flipped)
    result = []
    for f in sorted {
        result = append(result, [get(f, 1), get(f, 0)])
    }
    return result
}

pure fn format_pairs(pairs: [[Text, Number]]) -> Text {
    texts = []
    for p in pairs {
        city = get(p, 0)
        lat_text = to_text(get(p, 1))
        entry_text = join([city, ": ", lat_text], "")
        texts = append(texts, entry_text)
    }
    return join(texts, ", ")
}

