    repr = format_pairs(sorted_pairs)
    return describe_pattern(repr)
}

pure fn fib_seq(n: Number) -> [Number] {
    seq = [0, 1]
    for i in range(2, n) {
        prev1 = get(seq, i - 1)
        prev2 = get(seq, i - 2)
        seq = append(seq, prev1 + prev2)
    }
    return seq
}

pure fn seq_to_text(seq: [Number]) -> Text {
    parts = []
    for num in seq {
        parts = append(parts, to_text(num))
    }
    return join(parts, ", ")
}

intent explain_golden_ratio(sequence: Text) -> Text {
