    sequence_text = seq_to_text(sequence)
    explanation = explain_golden_ratio(sequence_text)
    return join([
        "Fibonacci sequence up to the 8th number: ",
        sequence_text,
        "\n\nExplanation: ",
        explanation
    ], "")
}

import summarize from "stdlib/language"

pure fn remove_stop_words(s: Text) -> Text {
    words = split(s, " ")
    filtered = []
    stop_words = ["the", "a", "an", "is", "in", "on", "at", "to"]
    for w in words {
        if lower(w) not in stop_words {
            filtered = append(filtered, w)
        }
    }
    return join(filtered, " ")
}

entry main(x: Text) {
    filtered = remove_stop_words(x)
    return summarize(filtered, 10)
}
